class Solution:
    def minDays(self, n: int) -> int:
        if n == 1:
            return 1
        if n % 2 == 0 and n % 3 == 0:
            return min(n // 2 + self.minDays(n // 2), 2 * (n // 3) + self.minDays(n - 2 * (n // 3)))
        elif n % 2 == 0:
            return min(n // 2 + self.minDays(n // 2), 1 + self.minDays(n - 1))
        elif n % 3 == 0:
            return min(2 * (n // 3) + self.minDays(n - 2 * (n // 3)), 1 + self.minDays(n - 1))
        else:
            return 1 + self.minDays(n - 1)
```
