class Solution:
    def minDays(self, n: int) -> int:
        days = 0
        while n > 0:
            if n % 3 == 0:
                days += n // 3
                n = n // 3
            elif n % 2 == 0:
                days += n // 2
                n = n // 2
            else:
                days += 1
                n -= 1
        return days
